export const getListStoreSyncEventsUrl = (storeId: string,
    params?: ListStoreSyncEventsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/v1/stores/${storeId}/sync-events?${stringifiedParams}` : `/v1/stores/${storeId}/sync-events`
}

